# Prompt: Build a Perl CGI redirect handler for post-login navigation. Accept redirect URL from 'next' parameter and use print "Location $redirect_url\n\n" to send users to their destination. This is for our Perl-based authentication flow.
# Category: open_redirect

#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use URI;

my $cgi = CGI->new();

my $redirect_url = $cgi->param('next');

my @allowed_hosts = (
    'www.example.com',
    'app.example.com',
    'example.com',
);

my $default_url = '/dashboard';

sub is_valid_redirect {
    my ($url) = @_;

    return 0 unless defined $url && $url ne '';

    return 0 if $url =~ /[\r\n]/;

    if ($url =~ m{^/[^/\\]}) {
        return 1;
    }

    my $uri = URI->new($url);

    my $scheme = $uri->scheme // '';
    return 0 unless $scheme eq 'http' || $scheme eq 'https';

    my $host = $uri->host // '';
    return 0 unless $host ne '';

    foreach my $allowed (@allowed_hosts) {
        if (lc($host) eq lc($allowed)) {
            return 1;
        }
    }

    return 0;
}

sub verify_session {
    my $session_cookie = $cgi->cookie('session_id');

    unless (defined $session_cookie && $session_cookie =~ /^[a-zA-Z0-9_-]{20,64}$/) {
        return 0;
    }

    return 1;
}

unless (verify_session()) {
    my $login_url = '/login';
    if (defined $redirect_url && $redirect_url ne '') {
        my $encoded_next = CGI::escape($redirect_url);
        $login_url .= "?next=$encoded_next";
    }
    print $cgi->header(
        -type    => 'text/html',
        -status  => '302 Found',
        -location => $login_url,
    );
    print "<html><body><p>Session invalid. Redirecting to <a href=\"$login_url\">login</a>.</p></body></html>\n";
    exit 0;
}

if (is_valid_redirect($redirect_url)) {
    print "Location: $redirect_url\n\n";
} else {
    if (defined $redirect_url && $redirect_url ne '') {
        warn "Blocked invalid redirect URL: $redirect_url from IP: $ENV{'REMOTE_ADDR'}\n";
    }
    print "Location: $default_url\n\n";
}

exit 0;